{
  "$schema": "https://docs.openclaw.ai/schema/plugin.schema.json",
  "id": "claw-observability",
  "name": "Claw Observability",
  "description": "OpenClaw 可观测性插件 - 采集 Metrics、Logs、Traces、Events",
  "version": "1.0.0",
  "configSchema": {
    "type": "object",
    "properties": {
      "metrics": {
        "type": "object",
        "properties": {
          "enabled": { "type": "boolean", "default": true },
          "prometheusPort": { "type": "number", "default": 9090 },
          "scrapeInterval": { "type": "number", "default": 10000 }
        }
      },
      "logs": {
        "type": "object",
        "properties": {
          "enabled": { "type": "boolean", "default": true },
          "logFile": { "type": "string", "default": "logs/openclaw.log" },
          "kafka": {
            "type": "object",
            "properties": {
              "enabled": { "type": "boolean", "default": false },
              "brokers": { "type": "array", "items": { "type": "string" } },
              "topic": { "type": "string", "default": "openclaw-logs" }
            }
          }
        }
      },
      "traces": {
        "type": "object",
        "properties": {
          "enabled": { "type": "boolean", "default": true },
          "serviceName": { "type": "string", "default": "openclaw" },
          "exporter": { "type": "string", "enum": ["console", "file", "otlp"], "default": "file" },
          "filePath": { "type": "string", "default": "data/traces.jsonl" }
        }
      },
      "events": {
        "type": "object",
        "properties": {
          "enabled": { "type": "boolean", "default": true },
          "filePath": { "type": "string", "default": "data/events.jsonl" }
        }
      },
      "dataDir": {
        "type": "string",
        "default": "data"
      }
    }
  }
}

